void PrintDeviceProperties(){
    cl_platform_id* platforms = NULL;
    cl_uint numPlatforms;
    cl_device_id* devices = NULL;
    cl_uint numDevices;
    cl_int status;

    status = clGetPlatformIDs(0, NULL, &numPlatforms);
    checkCLError(status, "Getting platform IDs");

    if (numPlatforms > 0) {
        platforms = (cl_platform_id*)malloc(numPlatforms * sizeof(cl_platform_id));
        status = clGetPlatformIDs(numPlatforms, platforms, NULL);
        checkCLError(status, "Getting platform IDs");
    } else {
        printf("No OpenCL platforms found\n");
        return;
    }

    printf("Total Device found: %d\n", numPlatforms);

    for (cl_uint nDeviceIdx = 0; nDeviceIdx < numPlatforms; ++nDeviceIdx) {
        status = clGetDeviceIDs(platforms[nDeviceIdx], CL_DEVICE_TYPE_ALL, 0, NULL, &numDevices);
        if (status != CL_SUCCESS || numDevices == 0) continue;

        devices = (cl_device_id*)malloc(numDevices * sizeof(cl_device_id));
        status = clGetDeviceIDs(platforms[nDeviceIdx], CL_DEVICE_TYPE_ALL, numDevices, devices, NULL);
        checkCLError(status, "Getting device IDs");

        for (cl_uint dIdx = 0; dIdx < numDevices; ++dIdx) {
            char name[256], vendor[256];
            cl_ulong globalMem;
            size_t sharedMem;
            cl_uint regsPerBlock, warpSize, maxThreadsPerBlock;
            size_t maxThreadsDim[3], maxGridSize[3];
            size_t totalConstMem;
            cl_uint major, minor, clockRate;
            size_t textureAlignment;
            cl_uint multiProcessorCount;

            clGetDeviceInfo(devices[dIdx], CL_DEVICE_NAME, sizeof(name), name, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_VENDOR, sizeof(vendor), vendor, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(globalMem), &globalMem, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_LOCAL_MEM_SIZE, sizeof(sharedMem), &sharedMem, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(maxThreadsPerBlock), &maxThreadsPerBlock, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_MAX_WORK_ITEM_DIMENSIONS, sizeof(maxThreadsDim), maxThreadsDim, NULL);
            // Grid size in OpenCL is effectively unlimited by hardware constraints in the same way, 
            but we query max compute units as a proxy for multi-processor count
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_MAX_COMPUTE_UNITS, sizeof(multiProcessorCount), &multiProcessorCount, NULL);
            clGetDeviceInfo(devices[dIdx], CL_DEVICE_VERSION, sizeof(name), name, NULL); // Reusing name buffer for version string roughly

            printf("\nDevice Name \t\t - %s ", name);
            printf("\n**************************************");
            printf("\nTotal Global Memory\t\t\t - %lu KB", globalMem/1024);
            printf("\nShared memory available per block \t - %lu KB", sharedMem/1024);
            printf("\nNumber of registers per thread block \t - N/A (OpenCL)"); // Not directly exposed
            printf("\nWarp size in threads \t\t\t - N/A (OpenCL)"); // Vector width might be proxy
            printf("\nMemory Pitch \t\t\t\t - N/A");
            printf("\nMaximum threads per block \t\t - %d", (int)maxThreadsPerBlock);
            printf("\nMaximum Thread Dimension (block) \t - %d %d %d", (int)maxThreadsDim[0], (int)maxThreadsDim[1], (int)maxThreadsDim[2]);
            printf("\nMaximum Thread Dimension (grid) \t - Unlimited (OpenCL)");
            printf("\nTotal constant memory \t\t\t - N/A");
            printf("\nOpenCL ver \t\t\t\t - %s", name);
            printf("\nClock rate \t\t\t\t - N/A");
            printf("\nTexture Alignment \t\t\t - N/A");
            printf("\nDevice Overlap \t\t\t\t - N/A");
            printf("\nNumber of Multi processors \t\t - %d\n\n", (int)multiProcessorCount);

            free(devices);
        }
    }
    free(platforms);
}










